// Build newsletter prompt from inputs
const news = $('Fetch Industry News').all().map(i => i.json);
const topics = $('Get Newsletter Topic Queue').first().json;

const topTopic = (topics.tasks || [])[0];
const topicName = topTopic?.name || 'RevOps best practices';
const topicNotes = topTopic?.description || '';

const newsItems = news.slice(0, 5).map(n => `- ${n.title}`).join('
');

// Calculate edition number (weeks since start)
const startDate = new Date('2025-01-01');
const editionNum = Math.floor((Date.now() - startDate) / (7 * 24 * 60 * 60 * 1000));

return [{
  json: {
    system_prompt: `You are a ghostwriter for a RevOps consultant's weekly Substack newsletter. The newsletter targets VP Sales, CROs, and RevOps leaders at B2B SaaS companies ($10-100M ARR).

**Newsletter voice:**
- More thoughtful and analytical than LinkedIn
- Like a smart friend who happens to be a RevOps expert explaining something over coffee
- Uses frameworks and mental models, not just tactics
- 800-1500 words, never padded
- Can be opinionated but always shows the reasoning

**Differentiation from LinkedIn:**
- LinkedIn = short tactical hits. Substack = deeper analysis and frameworks. Distinct content, not repurposed.`,
    user_prompt: `Write a draft for this week's Substack newsletter.

**Edition #:** ${editionNum}
**Week Of:** ${new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}

**Topic:** ${topicName}
**Topic Notes:** ${topicNotes}

**Recent Industry News:**
${newsItems}

---

Generate a newsletter with: Title, Subtitle, Estimated read time, then sections: Opening (100-150 words with hook), The Insight/Framework (300-500 words), Practical Application (200-300 words with steps), Closing (100-150 words tying back to opening). Include 1-2 pull quotes. Total 800-1500 words. Use informative subheadings. Bold key sentences for skimmers.`,
    model: 'gemini-pro',
    workflow_name: 'substack-newsletter',
    client_name: 'Self',
    purpose: 'Newsletter draft generation'
  }
}];
